    ADD CONSTRAINT "incidents_title_not_blank"
        CHECK (length(btrim("title")) > 0),
    ADD CONSTRAINT "incidents_description_not_blank"
        CHECK (length(btrim("description")) > 0),
    ADD CONSTRAINT "incidents_reference_number_format"
        CHECK ("reference_number" ~ '^INC-[0-9]{4}-[0-9]{6}$');

