-- ============================================================================
-- Seed: role_permission assignments using stable role/permission codes
-- ON CONFLICT DO NOTHING makes this idempotent.
-- ============================================================================

-- SUPER_ADMIN receives all 10 incident permissions
INSERT INTO "role_permissions" ("role_id", "permission_id")
SELECT r.id, p.id
FROM "roles" r
CROSS JOIN "permissions" p
WHERE r.code = 'SUPER_ADMIN'
  AND p.code IN (
      'incidents.read', 'incidents.create', 'incidents.update_own_draft',
      'incidents.review', 'incidents.assign', 'incidents.investigate',
      'incidents.resolve', 'incidents.close', 'incidents.comment',
      'incidents.manage'
  )
ON CONFLICT ("role_id", "permission_id") DO NOTHING;

-- ADMIN receives all 10 incident permissions
INSERT INTO "role_permissions" ("role_id", "permission_id")
SELECT r.id, p.id
FROM "roles" r
CROSS JOIN "permissions" p
WHERE r.code = 'ADMIN'
  AND p.code IN (
      'incidents.read', 'incidents.create', 'incidents.update_own_draft',
      'incidents.review', 'incidents.assign', 'incidents.investigate',
      'incidents.resolve', 'incidents.close', 'incidents.comment',
      'incidents.manage'
  )
ON CONFLICT ("role_id", "permission_id") DO NOTHING;

-- VIEWER receives 4 incident permissions (report and track own incidents)
INSERT INTO "role_permissions" ("role_id", "permission_id")
SELECT r.id, p.id
FROM "roles" r
CROSS JOIN "permissions" p
WHERE r.code = 'VIEWER'
  AND p.code IN (
      'incidents.read', 'incidents.create',
      'incidents.update_own_draft', 'incidents.comment'
  )
ON CONFLICT ("role_id", "permission_id") DO NOTHING;
